using System;

class Program
{
    static void Main()
    {
        // Implicit
        int num = 123;
        double bigNum = num;
        Console.WriteLine($"Implicit: {bigNum}");

        // Explicit
        double pi = 3.14159;
        int truncated = (int)pi;
        Console.WriteLine($"Explicit: {truncated}");

        // Convert class
        string text = "456";
        int parsed = Convert.ToInt32(text);
        Console.WriteLine($"Converted: {parsed}");
    }
}
